  `hours` int NOT NULL DEFAULT '0',
  `hours_o` int NOT NULL DEFAULT '0',
  `hours_z` int NOT NULL DEFAULT '0',
  `hours_l` int NOT NULL DEFAULT '0',
  `hours_p` int NOT NULL DEFAULT '0',
  `hours_s` int NOT NULL DEFAULT '0',
  `hours_a` int NOT NULL DEFAULT '0',
  `hours_k` int NOT NULL DEFAULT '0',
  `hours_i` int NOT NULL DEFAULT '0',
  `form` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL DEFAULT '',
  `form1` varchar(8) CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL DEFAULT '',
  `form2` varchar(8) CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL DEFAULT '',
  `form3` varchar(8) CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL DEFAULT '',
  `att_i` varchar(60) CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL DEFAULT '',
  `norm_hours` int NOT NULL DEFAULT '8',
  `p0` text CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL,
  `p1` text CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL,
  `p2` text CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL,
  `p3` text CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL,
  `p4` text CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL,
  `p5` text NOT NULL,
  `p6` text CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL,
  `s_fl` varchar(16) CHARACTER SET utf8mb3 COLLATE utf8_general_ci NOT NULL DEFAULT 'Самоподготовка',
  PRIMARY KEY (`id`),
  KEY `name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=70 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
