INSERT INTO `p_rprg` VALUES (42,0,'«Технология повышения эффективности производства. Цифровые компетенции и AGILE-компетенции»',240,22,80,80,22,80,0,0,16,'','','','true','итоговая аттестационная работа',8,'','Дополнительная профессиональная программа повышения квалификации  «Технология повышения эффективности производства. Цифровые компетенции и AGILE-компетенции»  разработана для повышения квалификации и овладения слушателями новых компетенций, необходимых для применения в работе руководителей среднего звена, специалистов. \nВ процессе обучения слушатели получают системное представление о современном состоянии технологиях повышения эффективности производства, цифровых компетенциях и AGILE-компетенции. Слушателям дается представление о связи коммуникационных техник с эмоциональным интеллектом и особенностью поведения работников разных поколений. Формируется представление о факторах успешного развития проектных и управленческих команд. \nОдной из главных задач освоения программы является участие каждого слушателя в междисциплинарном проекте: «прокачиваются» навыки, полученные в теоретической части курса командной работы, закрепляются на практике полученные на очных занятиях навыки.','Очная часть обучения проводится в формате традиционных лекций, тренингов, используются следующие интерактивные методы обучения:\n- тренинги: мини-лекции с демонстрацией презентационных материалов, видеоматериалов;\n- вебинары;\n- семинары;\n- практические упражнения с контролем выполнения в соревновательной форме;\n- дискуссии;\n- ролевые и ситуационные игры;\n- производственные кейсы и междисциплинарные проекты.\nЗакрепление освоенного учебного материала проводится после каждого учебного модуля теоретической части. \nЗаочная часть программы обучения проводится в системе дистанционного обучения. Слушатели получают доступ к учебным модулям программы, методист, курирующий обучение, контролирует обучение слушателей программы. Кроме того,  система дистанционного обучения формирует отчет о выполнении элементов курса по каждому слушателю. \nВо время прохождения стажировки слушатели выполняют междисциплинарные проекты по актуальным производственным темам (в том числе и по импортозамещению), закрепляют на практике усвоенные теоретические знания. При этом слушателей распределяют по проектным командам (категорически не по отделам) для повышения квалификации и овладения навыками командной работы и горизонтальной ротации.\nИтоговая  аттестация представляет собой публичную защиту междисциплинарных проектов. Перед защитой итоговой работы слушателям проводится консультация по оформлению  междисциплинарных проектов, презентаций для защиты, управлению аудиторией при публичном выступлении. \nСлушатели постоянно имеют доступ к сопровождению и поддержке со стороны кураторов программы, методистов и организаторов обучения АНО ДПО «ЦППК». В случае производственной загруженности слушатели, пропустившие то или иное занятие, могут изучить записи занятий  в системе  дистанционного обучения.\nРезультаты освоения программы\nВ результате освоения содержания программы слушатели должны знать:\n- методы эффективных коммуникаций; \n- инструменты управления рабочим временем; \n- инструменты производственной системы;\n- Agile технологию;\n- особенности организационного поведения работников разных поколений;\n- методы управление стрессом.\nуметь: \n- применять инструменты Бережливого производства и временем; \n- оказывать  психологическую  помощь и поддержку;\n- применять Agile технологию;\n- управлять стрессом. \nВладеть навыками: \n- взаимодействия в команде (в том числе и во временных проектных командах);  \n- лидерства;\n- коммуникации.','','','','Итоговая аттестация проходит в форме итогового тестирования.\nКритерии оценивания итогового тестирования:\nОценка за контроль ключевых компетенций обучающихся производится по пятибалльной системе. При выполнении заданий ставится отметка:\n\n«3» - за 50-70% правильно выполненных заданий,\n«4» - за 70-85%  правильно выполненных заданий,\n«5» - за правильное выполнение более 85% заданий.','Самоподготовка'),(43,0,'Цифровая экономика и трансформация предприятия',240,6,4,4,8,2,0,2,2,'','','','','Итоговая  аттестация: квалификационный экзамен',8,'','','','','','','','Самоподготовка'),(44,0,'«Повышение производительности труда работников основного  производства и ремонтно-обслуживающего персонала»',320,0,0,2,3,0,0,0,0,'','','','','',8,'','','','','','','','Стажировка'),(57,0,'Повышение эффективности производства. Управление персоналом',240,0,0,0,0,0,0,0,0,'','','','','',8,'Дополнительная профессиональная программа повышения квалификации __________________________________разработана в соответствии с нормами Федерального закона от 29 декабря 2012 г. № 273-ФЗ \"Об образовании в Российской Федерации\" и с учетом требований Порядка организации и осуществления образовательной деятельности по дополнительным профессиональным программам, утвержденного приказом Министерства образования и науки Российской Федерации от 1 июля 2013 г. № 499,','Целью реализации программы может быть совершенствование и (или) получение новой компетенции, необходимой для профессиональной деятельности, и (или) повышение профессионального уровня в рамках имеющейся квалификации.Пример: Целью реализации программы является повышение профессионального уровня ППС отделения «наименование отделения» в области «наименование области изучения/темы» в рамках имеющейся квалификации для непрерывного развития и совершенствования профессиональных компетенций, внедрения современных инновационных подходов в обучении студентов.','В результате освоения программы совершенствуются следующие компетенции:    1. …     2. … Слушатель должен приобрести следующие знания и умения, необходимые для качественного изменения компетенций: Слушатель должен знать: - … - Слушатель должен уметь: - … -','','','','','Самоподготовки'),(63,0,'Тракторист категории \"С\"',464,0,0,320,96,0,0,48,0,'','true','','','',8,'Дополнительная профессиональная программа повышения квалификации __________________________________разработана в соответствии с нормами Федерального закона от 29 декабря 2012 г. № 273-ФЗ \"Об образовании в Российской Федерации\" и с учетом требований Порядка организации и осуществления образовательной деятельности по дополнительным профессиональным программам, утвержденного приказом Министерства образования и науки Российской Федерации от 1 июля 2013 г. № 499,','Целью реализации программы может быть совершенствование и (или) получение новой компетенции, необходимой для профессиональной деятельности, и (или) повышение профессионального уровня в рамках имеющейся квалификации.Пример: Целью реализации программы является повышение профессионального уровня ППС отделения «наименование отделения» в области «наименование области изучения/темы» в рамках имеющейся квалификации для непрерывного развития и совершенствования профессиональных компетенций, внедрения современных инновационных подходов в обучении студентов.','В результате освоения программы совершенствуются следующие компетенции:    1. …     2. … Слушатель должен приобрести следующие знания и умения, необходимые для качественного изменения компетенций: Слушатель должен знать: - … - Слушатель должен уметь: - … -','','','','','Самоподготовка'),(67,0,'Химводоочистка (водоподготовка) и водно-химический режим котельных, тепловых электрических станций и тепловых сетей',72,8,64,64,8,40,0,4,4,'','','','true','Проверка знаний: тестирование',8,'Образовательная программа по курсу «Химводоочистка (водоподготовка) и водно-химический режим котельных, тепловых электрических станций и тепловых сетей» разработана учебно-методическим отделом АНО ДПО «Центр профессиональной подготовки кадров» для повышения кадрового потенциала работников из числа руководителей и специалистов, осуществляющих работы, связанные  c подготовкой и ведением химводоочистки (водоподготовки) и водно-химического режима котельных, тепловых электрических станций и тепловых сетей, в соответствии с Федеральным законом от 29.12.2012 N 273-ФЗ «Об образовании в Российской Федерации», Приказа Министерства образования и науки РФ от 01.07.2013 г. № 499 «Об утверждении порядка организации и осуществления образовательной деятельности  по дополнительным профессиональным программам», на основе действующих нормативно-правовых актов регламентирующих работы, связанные  c подготовкой и ведением химводоочистки (водоподготовки) и водно-химического режима котельных, тепловых электрических станций и тепловых сетей, с учетом требований Правил технической эксплуатации электрических станций и сетей РФ, Правил организации технического обслуживания и ремонта объектов электроэнергетики, Федеральных норм и правил в области промышленной безопасности «Правила безопасности химически опасных производственных объектов», Федеральных норм и правил в области промышленной безопасности «Правила безопасности опасных производственных объектов, при использовании оборудования, работающего под избыточным давлением», Правил техники безопасности при эксплуатации тепломеханического оборудования электростанций и тепловых сетей и других нормативно-технических документов, с учетом требований Заказчика.','Целью реализации программы является формирование у слушателей компетенций, необходимых для профессиональной деятельности, изучение устройства оборудования, технологичических процессов и технологии выполнения работ, приобретение знаний, умений и навыков безопасного выполнения работ, в объеме требований действующих нормативно-правовых актов регламентирующих работы, связанные  c подготовкой и ведением химводоочистки (водоподготовки) и водно-химического режима котельных, тепловых электрических станций и тепловых сетей.\nКурс предназначен для повышения квалификации руководителей и специалистов организующих работы по наладке, вводу в эксплуатацию, технического и оперативного обслуживания, а также ремонта систем химводоочистки (водоподготовки) и ведения водно-химического режима котельных, тепловых электрических станций и тепловых сетей.','Слушатель в результате освоения программы должен обладать следующими профессиональными компетенциями:\n	общими понятиями о подготовке и ведении химводоочистки (водоподготовки) и водно-химического режима котельных, тепловых электрических станций и тепловых сетей;\n	порядком проведения работ по подготовке и ведению химводоочистки (водоподготовки) и водно-химического режима котельных, тепловых электрических станций и тепловых сетей; \n	навыками подготовки исполнительной документации, составления инструкций по эксплуатации и режимных карт, оформление проектов производства работ и нарядов-допусков.\n\nПо окончании обучения по программе «Химводоочистка (водоподготовка) и водно-химический режим котельных, тепловых электрических станций и тепловых сетей» слушатель\n должен знать:\n	 требования нормативно – технических и справочных документов;\n	основные технические характеристики оборудования; \n	технологические ограничения и указания по ведению режима; \n	требования безопасности; \n	порядок проведения работ по организации химводоочистки (водоподготовки) и водно-химического режима, в том числе новых, после расширения, реконструкции и ремонта;\n	организацию водно-химического режима при нарушениях;\n	требования по предупреждению и ликвидации нарушений водно-химического режима;\n	требования к оформлению документации.\nдолжен уметь:\n	организовать, провести и обеспечить контроль соблюдения химводоочистки (водоподготовки) и водно-химического режима котельных, тепловых электрических станций и тепловых сетей (как вновь вводимых, так и действующих);\n	оформлять документацию по подготовке и ведению химводоочистки (водоподготовки) и водно-химического режима котельных, тепловых электрических станций и тепловых сетей;','1. Какие условия для надежной и безопасной эксплуатации должны быть выполнены перед пробным пуском законченного строительством энергообъекта?     \nА)	Только условия по укомплектованию, обучению (с проверкой знаний) эксплуатационного и ремонтного персонала; разработке и утверждению эксплуатационных инструкций, инструкций по охране труда, оперативных схем, технической документации по учету и отчетности.\nБ)	Только условия по монтажу и наладке систем контроля и управления, условия по вводу в действие средств оперативно-диспетчерского и технологического управления с линиями связи, системы пожарной сигнализации и пожаротушения, аварийного освещения, вентиляции; условия по подготовке запасов топлива, материалов, инструмента и запасных частей.\nВ)	Только условия по получению разрешения на эксплуатацию энергообъекта от органов государственного контроля и надзора.\nГ)	Должны быть выполнены все перечисленные условия.\n2. С какого момента ответственность за сохранность оборудования энергообъекта несет организация-заказчик? \nА)	После завершения комплексного опробования энергоустановки.\nБ)	После получения разрешения на эксплуатацию энергообъекта от органов государственного контроля и надзора.\nВ)	С момента подписания акта приемки рабочей комиссией, которая принимает оборудование после проведения его индивидуальных испытаний для комплексного опробования.\nГ)	После подписания акта государственной комиссией.\n3. Какие мероприятия не включаются в объем периодического технического освидетельствования оборудования, зданий и сооружений энергообъекта, проводимого на основании действующих нормативно-технических документов? \nА)	Наружный и внутренний осмотр.\nБ)	Выполнение предписаний органов государственного контроля и надзора и мероприятий, разработанных при предыдущем техническом освидетельствовании.\nВ)	Проверка технической документации.\nГ)	Испытания на соответствие условиям безопасности оборудования, зданий                            и сооружений.\n4. Что из перечисленного не включает в себя оценка качества ремонта оборудования? \nА)	Оценку качества отремонтированного оборудования.\nБ)	Оценку качества выполненных ремонтных работ.\nВ)	Оценку уровня пожарной безопасности.\nГ)	Проверку временной эксплуатационной документации.\n5. В каком случае не должны проводиться эксплуатационные испытания котла для составления режимной карты и корректировки инструкции по эксплуатации? \nА)	При вводе котла в эксплуатацию.\nБ)	После капитального ремонта.\nВ)	После внесения конструктивных изменений.\nГ)	При переходе на другой вид или марку топлива.\nД)	Для выяснения причин отклонения параметров от заданных.\n6. Какой срок по устранению причин ухудшения качества пара по нормам содержания соединений натрия, кремниевой кислоты и удельной электрической проводимости для котлов с естественной циркуляцией указан неверно? \nА)	При превышении норм не более чем в 1,5 раза причина должна быть устранена                 в течение 4 суток.\nБ)	При превышении норм не более чем в 2 раза причина должна быть устранена                     в течение 72 часов.\nВ)	При превышении норм не более чем от 2 до 4 раз причина должна быть устранена     в течение 24 часов.\nГ)	При неустранении нарушений в установленные сроки, а также при превышении норм более чем в 4 раза или снижении рН ниже 5,5 турбина на блочных электростанциях или котел на электростанциях с поперечными связями должны быть остановлены не позднее чем через 24 часа по решению технического руководителя электростанции с уведомлением диспетчера энергосистемы.\n7. С кем должны быть согласованы включение в работу и отключение любого оборудования, которые могут вызывать ухудшение качества воды и пара? \nА)	С техническим руководителем электростанции.\nБ)	С химической службой энергосистемы.\nВ)	С химическим цехом (лабораторией или соответствующим подразделением).\nГ)	С вышестоящей организацией.\nД)	С организацией, установившей действующие нормы качества.\n8. С кем должны быть согласованы любые изменения проектных схем                                    и конструкций оборудования, которые могут влиять на работу водоподготовительных установок и установок для очистки конденсатов, а также на водно-химический режим электростанции (тепловых сетей)? \nА)	С техническим руководителем электростанции.\nБ)	С химической службой энергосистемы.\nВ)	С химическим цехом (лабораторией или соответствующим подразделением).\nГ)	С вышестоящей организацией.\nД)	С проектной организацией.\n9. Каково допустимое превышение норм качества сетевой воды в начале отопительного сезона и в послеремонтный период (в течение 4 недель) для закрытых систем теплоснабжения? \nА)	По содержанию соединений железа - до 0,5 мг/дм3, растворенного кислорода - до 15 и взвешенных веществ - до 30 мг/дм3. \nБ)	По содержанию соединений железа - до 1,0 мг/дм3, растворенного кислорода - до 30 и взвешенных веществ - до 15 мг/дм3. \nВ)	По содержанию соединений железа - до 1,2 мг/дм3, растворенного кислорода - до 30 и взвешенных веществ - до 15 мг/дм3. \nГ)	По содержанию соединений железа - до 2 мг/дм3, растворенного кислорода - до                30 и взвешенных веществ - до 20 мг/дм3. \n10. На какой срок в открытых системах теплоснабжения по согласованию                              с органами санитарно-эпидемиологической службы, допускается отступление от действующих норм для питьевой воды по показателям цветности до 70°                                      и содержанию железа до 1,2 мг/дм3 в период сезонных включений эксплуатируемых систем теплоснабжения, присоединения новых, а также после их ремонта? \nА)	В течение 7 суток.\nБ)	В течение 14 суток.\nВ)	В течение 21 дня.\nГ)	В течение 28 суток.\n11. Какие требования безопасности должны быть выполнены при работе                               с гидразингидратом? \nА)	Сливать гидразингидрат из бочек следует с помощью сифона или эжектора из нержавеющей стали в приемный бак, наполовину заполненный водой.\nБ)	При работе с гидразингидратом необходимо пользоваться прорезиненным фартуком, резиновыми перчатками, защитными очками и фильтрующим противогазом марки КД или А.\nВ)	Случайно пролитый гидразингидрат должен быть смыт водой в дренажный приямок и нейтрализован хлорной известью или гипохлоритом натрия.\nГ)	Все перечисленные требования безопасности.\n12. Какие требования безопасности должны быть выполнены при подготовке                      и проведении химической очистки теплосилового оборудования? \nА)	Работы по химической очистке теплосилового оборудования производятся по специальной программе, утвержденной главным инженером предприятия.\nБ)	Ответственным за проведение инструктажа по мерам безопасности при работе                    с химическими реагентами и за процесс химической очистки является начальник химического цеха.\nВ)	Ответственным за безопасность персонала, выделенного для этой работы, является начальник цеха, в ведении которого находится промываемое оборудование.\nГ)	Все перечисленные требования безопасности.\n13. Какие требования безопасности необходимо соблюдать при использовании в работе кислот и щелочей?   \nА)	Кислоты, щелочи должны храниться в изолированных от рабочих помещений складах-цистернах или в баках, на которых должны быть четкие надписи                               с наименованием реагента.\nБ)	Концентрированная серная кислота, растворы щелочи должны храниться                               в стальных емкостях.\nВ)	Емкости для хранения кислот и щелочей должны сообщаться с атмосферой посредством воздушников и иметь указатели уровня и переливные трубы.\nГ)	Все перечисленные требования безопасности.\n14. Что контролируется при проведении проверки готовности котла к пуску в работу?\n\nА)	Наличие документации по результатам пуско-наладочных испытаний и комплексного опробования.\nБ)	Исправность питательных приборов котла и соответствие их проекту.\nВ)	Соответствие водно-химического режима котла требованиям  ФНП ОРПД.\nГ)	Наличие должностных инструкций для ответственных лиц и специалистов, осуществляющих эксплуатацию котла.\n15. Какие котлы перед вводом в эксплуатацию после монтажа подвергаются очистке совместно с основными трубопроводами и другими элементами водяного (парового) тракта?\n\nА)	Все паровые котлы независимо от давления.\nБ)	Паровые котлы с давлением 10 МПа и выше.\nВ)	Прямоточные  котлы с давлением 10 МПа и выше.\nГ)	Водогрейные котлы.\n\n16. Какое требование к заполнению котла водой перед растопкой указано неверно?\n\nА)	Перед растопкой барабанный котел должен быть заполнен химически очищенной и деаэрированной питательной водой.\nБ)	Перед растопкой прямоточный котел должен быть заполнен деаэрированной водой.\nВ)	При отсутствии в котельной деаэрационной установки перед растопкой допускается заполнять чугунные котлы химически очищенной водой.\nГ)	Заполнение неостывшего барабанного котла разрешается при температуре металла верха опорожненного барабана не выше 160 оС.\n17. Какие из приведенных котлов не оборудуются установками для докотловой обработки воды?\n\nА)	Паровые котлы с естественной циркуляцией и паропроизводительностью менее   0,7 т/час. \nБ)	Водогрейные котлы тепловой мощностью до 12 ГДж/час.\nВ)	Прямоточные котлы паропроизводительностью менее 0,7 т/час.\nГ)	Все приведенные котлы не оборудуются установками докотловой обработки воды.\n\n18. Какое условие должно выполняться для обеспечения безопасности котлов, не оборудованных установками докотловой обработки воды?\n\nА)	Повышенный расход непрерывной продувки котла, определяемый инструкцией по эксплуатации.\nБ)	Проведение чисток котла  с периодичностью при условии,  чтобы толщина отложений на наиболее теплонапряженных участках к моменту остановки котла не превышала 1 мм.\nВ)	Проведение периодических чисток котла в зависимости от показателей жесткости питательной и щелочности котловой воды.\nГ)	Проведение чисток котла  с периодичностью при условии,  чтобы толщина отложений на наиболее теплонапряженных участках к моменту остановки котла не превышала 0,5 мм.\n\n19. Какое требование к подпитке котлов сырой водой указано неверно?\n\nА)	Подпитка сырой водой котлов, оборудованных устройствами для докотловой обработки воды, не допускается.\nБ)	Каждый случай подпитки котлов сырой водой должен фиксироваться в журнале по водоподготовке (водно-химическому режиму) с указанием длительности подпитки и качества питательной воды в этот период.\nВ)	Когда проектом предусмотрена в аварийных ситуациях подпитка котла сырой водой, котлы должны работать на сниженных температурных параметрах с температурой теплоносителя на выходе из котла не более 90 оС.\nГ)	Все требования указаны верно.\n\n20. Кем устанавливается периодичность отбора проб исходной, химочищенной, котловой, сетевой, питательной и подпиточной воды, конденсата и пара?\n\nА)	Организацией-изготовителем котла.\nБ)	Наладочной организацией.\nВ)	Эксплуатирующей организацией.\nГ) Экспертной организацией.	\n\n21. Кем вносятся сведения в ремонтный журнал котла о выполненных ремонтных работах, примененных материалах, сварке и сварщиках, об остановке котлов на чистку и промывку?\n\nА)	Ответственным за осуществление производственного контроля за безопасной эксплуатацией оборудования, работающего под давлением.\nБ)	Ответственным за исправное состояние и безопасную эксплуатацию котла.\nВ)	Уполномоченным представителем специализированной ремонтной организации.\nГ)	Лицо, которое вносит сведения в ремонтный журнал котла, определяется распорядительными документами эксплуатирующей организации.\n\n22.  Каким путем осуществляется ведение контроля за внутренней коррозией водяных тепловых сетей\nА)  анализом сетевой воды и конденсата\nБ)  по внешнему виду сетевой воды и конденсата\nВ)  по результатам выборочного вскрытия трубы\nГ)  при проведении испытаний\n\n23.  Разрешается или нет производить разбор сетевой воды из закрытых систем горячего водоснабжения\nА)  разрешается\nБ)  разрешается в особых случаях\nВ)  разрешается с письменного распоряжения руководителя организации, эксплуатирующей систему\nГ) не допускается\nД)  разрешается по требованию Ростехнадзора\n\n24.  Для контроля каких параметров теплоносителя тепловая сеть должна быть оборудована отборными устройствами для измерения:\nА) расхода теплоносителя\nБ) температуры и давления воды в подающих и обратных трубопроводах, давления пара\nВ) расхода тепловой энергии\nГ) давления пара\n\n25. Требования к промывке сетей после ремонта\nА) до полного осветления воды\nБ) однократным объемом воды\nВ) семикратным объемом воды\nГ) двукратным объемом воды\nД) десятикратным объемом воды\n\n26.  Укажите наибольший срок временного допуска для наладки, опробования и приемки в работу тепловой энергоустановки\nА) не более 1 месяца\nБ) не более 72 часов\nВ) не более 3 месяцев\nГ) не более 6 месяцев\nД) не более 12 месяцев\n\n27. Какая информация указывается на запорной и регулирующей арматуре\n\nА) допустимые температура и давление теплоносителя\nБ) направление движения теплоносителя, номер по схеме и указатели направления открытия и закрытия\nВ) дата установки и монтажа, сроки до регламентируемой замены и профилактических ремонтов\nГ) условный диаметр и допустимое давление для арматуры по техническим характеристикам\n\n28.  Возможна ли непосредственная присадка гидразина в подпиточную воду тепловых сетей\n\nА) не допускается\nБ) допускается, если это указано в паспорте оборудования\nВ) допускается по разрешению предприятия-изготовителя котельного оборудования\nГ) допускается по разрешению технического руководителя эксплуатирующей организации\nД) допускается в особых случаях','Банин Владимир Рюрикович','Мультимедийное оборудование, компьютеры.\nОбучающе - контролирующая система «ОЛИМПОКС», дает возможность проведения обучения и проверки знаний, проведения тестирования и анализ результатов и др.\nВысокоскоростной канал связи с резервированием, ноутбук, видеокамера, микрофон\nПрограммное обеспечение «Среда дистанционного обучения Русский Moodle 3KL Норм 3.5.3а», возможность проведения обучения и проверки знаний, проведения тестирования и анализ результатов и др. Интеграция данных об обученности персонала в существующую базу данных Заказчика\nПрограммное обеспечение «АМК Система», возможность проведения обучения и проверки знаний, проведения тестирования и анализ результатов и др.\n','В качестве промежуточного контроля слушателям предлагается оформить образцы документации – проектов производства работ, нарядов-допусков, исполнительной документации (актов скрытых работ и актов выполненных работ). Критерием правильности заполнения считается соответствие содержания документации характеру выполняемой работы.\nВ качестве итоговой аттестации слушателям предлагается пройти тестирование. Количество предлагаемых слушателю  вопросов составляет 20 вопросов, время  тестирования составляет  20 минут, количество попыток – не более 5 раз. \nВ вопросах с множественным выбором (тестовые вопросы с множественным выбором ответа предполагают выбор нескольких правильных ответов из ряда предложенных) верным будет считаться ответ, если указаны все правильные ответы.\nПо завершению тестирования слушателю представляется результат тестирования в виде баллов и оценки, количества правильно и неправильно отвеченных вопросов. Для объективной проверки знаний были установлены единые критерии для всех проходящих тестирование. Итоговая аттестация считается успешно пройденной, если слушатель получил 18 и более баллов, правильно ответил на 18 и более вопросов.','Самоподготовка'),(68,0,'Программа профессионального обучения - программа профессиональной подготовки по профессии \"осмотрщик-ремонтник вагонов\"',320,0,0,80,40,20,0,8,8,'','','','true','Квалификационный экзамен: итоговая квалификационная работа',8,'','Программа направлена на освоение новых трудовых функций (приобретение обучающимися новых профессиональных компетенций  (ПК) и специальных компетенций (СК)), необходимых для осуществления профессиональной деятельности по профессии \"осмотрщик-ремонтник вагонов\".\n','Обучающийся должен освоить следующие трудовые функции (приобрести профессиональные компетенции, которые соответствуют обобщенным трудовым функциям ОТФ С и ОТФ D:\nТрудовые функции, соответствующие ОТФ С и ОТФ D\n\n1. Техническое обслуживание и безотцепочный ремонт вагонов (ПМ 1/ПК 1)\n\nС/01.3 Техническое обслуживание грузовых вагонов и контейнеров, безотцепочный ремонт узлов, приборов вагонов при отсутствии средств диагностики коммерческих неисправностей на ходу поезда\n\nD/01.3 Техническое обслуживание грузовых вагонов и контейнеров с устранением неисправностей в коммерческом отношении при наличии диагностики коммерческих неисправностей на ходу поезда, безотцепочный ремонт вагонов\n\n2. Отцепка вагонов в ремонт (ПМ 2/ПК 2)\n\nC/02.3 Подготовка к отцепке грузовых вагонов в ремонт, сдача в ремонт контейнеров\n\nD/02.3 Подготовка к отцепке грузовых вагонов в ремонт, сдача в ремонт контейнеров\n\n3. Организация работы при техническом обслуживании вагонов (ПМ 3/ПК 3)\n\nC/03.3 Организация работы при техническом обслуживании грузовых вагонов и контейнеров, безотцепочном ремонте узлов, приборов вагонов при отсутствии средств диагностики коммерческих неисправностей на ходу поезда\n\nD/03.3 Организация работы при техническом обслуживании грузовых вагонов и контейнеров с устранением неисправностей на ходу поезд, безотцепочном ремонте вагонов и контейнеров с устранением неисправностей в техническом и коммерческом отношении при наличии средств диагностики коммерческих неисправностей на ходу поезда, безотцепочном ремонте вагонов\n\nДополнительно обучающийся осваивает модули \"Общепрофессиональный модуль (ОПМ/ОПК)\", специальные модули (СМ/СК) \"Безопасные методы и приемы выполнения работ на высоте (СМ 1/СК 1)\" и \"Работа в зимний период (СМ 2/СК 2)\", которые включают в себя специальный теоретический модуль (СТМ/СК) и специальный производственный модуль (СПМ/СК).\nПеречень знаний, умений, практического опыта (трудовых действий) для общепрофессионального модуля/общепрофессиональной компетенции, каждого профессионального модуля/профессиональной компетенции и специального модуля/специальной компетенции приведен в рабочих программах модулей.','','','','','Самоподготовка'),(69,0,'Программа профессионального обучения - программа профессиональной подготовки по профессии \"осмотрщик-ремонтник вагонов\"',320,0,0,0,0,0,0,0,0,'','','','','',8,'Дополнительная профессиональная программа повышения квалификации __________________________________разработана в соответствии с нормами Федерального закона от 29 декабря 2012 г. № 273-ФЗ \"Об образовании в Российской Федерации\" и с учетом требований Порядка организации и осуществления образовательной деятельности по дополнительным профессиональным программам, утвержденного приказом Министерства образования и науки Российской Федерации от 1 июля 2013 г. № 499,','Целью реализации программы может быть совершенствование и (или) получение новой компетенции, необходимой для профессиональной деятельности, и (или) повышение профессионального уровня в рамках имеющейся квалификации.\n Пример: Целью реализации программы является повышение профессионального уровня ППС отделения «наименование отделения» в области «наименование области изучения/темы» в рамках имеющейся квалификации для непрерывного развития и совершенствования профессиональных компетенций, внедрения современных инновационных подходов в обучении студентов.','В результате освоения программы совершенствуются следующие компетенции:\n    1. …\n     2. …\n Слушатель должен приобрести следующие знания и умения, необходимые для качественного изменения компетенций:\n Слушатель должен знать: - …\n - Слушатель должен уметь: - … -','','','','Итоговая аттестация проходит в форме итогового тестирования.\n Критерии оценивания итогового тестирования:\n Оценка за контроль ключевых компетенций обучающихся производится по пятибалльной системе. При выполнении заданий ставится отметка:\n «3» - за 50-70% правильно выполненных заданий,\n «4» - за 70-85%  правильно выполненных заданий,\n «5» - за правильное выполнение более 85% заданий.','Самоподготовка');
